# Arrays & Strings Cheat Sheet

## 1. Core Concepts
- **Array**: contiguous block of memory, O(1) random access, O(n) insert/delete at middle
- **String**: immutable in JS/Java/Python; use array + join for mutations
- Zero-indexed; length property for bounds; slice is exclusive of end index

## 2. Two Pointers
```typescript
// Opposite ends — palindrome check
function isPalindrome(s: string): boolean {
  let l = 0, r = s.length - 1;
  while (l < r) { if (s[l] !== s[r]) return false; l++; r--; }
  return true;
}
// Same direction — remove duplicates in-place
function removeDuplicates(nums: number[]): number {
  let slow = 1;
  for (let fast = 1; fast < nums.length; fast++)
    if (nums[fast] !== nums[fast-1]) nums[slow++] = nums[fast];
  return slow;
}
// 3Sum — sort + fix one + two pointers
function threeSum(nums: number[]): number[][] {
  nums.sort((a,b) => a-b);
  const res: number[][] = [];
  for (let i = 0; i < nums.length-2; i++) {
    if (i > 0 && nums[i] === nums[i-1]) continue;
    let l = i+1, r = nums.length-1;
    while (l < r) {
      const s = nums[i]+nums[l]+nums[r];
      if (s === 0) { res.push([nums[i],nums[l],nums[r]]); while(l<r&&nums[l]===nums[l+1])l++; while(l<r&&nums[r]===nums[r-1])r--; l++; r--; }
      else if (s < 0) l++; else r--;
    }
  }
  return res;
}
```

## 3. Sliding Window
```typescript
// Fixed window — max sum subarray of size k
function maxSumFixed(nums: number[], k: number): number {
  let sum = nums.slice(0,k).reduce((a,b)=>a+b,0), max = sum;
  for (let i = k; i < nums.length; i++) { sum += nums[i]-nums[i-k]; max = Math.max(max,sum); }
  return max;
}
// Variable window — longest substring without repeating chars (LC 3)
function lengthOfLongestSubstring(s: string): number {
  const seen = new Map<string,number>();
  let left = 0, max = 0;
  for (let r = 0; r < s.length; r++) {
    if (seen.has(s[r]) && seen.get(s[r])! >= left) left = seen.get(s[r])!+1;
    seen.set(s[r], r);
    max = Math.max(max, r-left+1);
  }
  return max;
}
// Minimum window substring (LC 76)
function minWindow(s: string, t: string): string {
  const need = new Map<string,number>();
  for (const c of t) need.set(c,(need.get(c)??0)+1);
  let have=0, required=need.size, left=0, minLen=Infinity, minStart=0;
  const win = new Map<string,number>();
  for (let r = 0; r < s.length; r++) {
    const c = s[r]; win.set(c,(win.get(c)??0)+1);
    if (need.has(c) && win.get(c)===need.get(c)) have++;
    while (have===required) {
      if (r-left+1 < minLen) { minLen=r-left+1; minStart=left; }
      const lc=s[left]; win.set(lc,win.get(lc)!-1);
      if (need.has(lc) && win.get(lc)!<need.get(lc)!) have--;
      left++;
    }
  }
  return minLen===Infinity ? '' : s.slice(minStart,minStart+minLen);
}
```

## 4. Prefix Sums
```typescript
function buildPrefix(nums: number[]): number[] {
  const p=[0]; for (const n of nums) p.push(p[p.length-1]+n); return p;
}
const rangeSum=(p:number[],l:number,r:number)=>p[r+1]-p[l];
// Subarray sum equals k (LC 560)
function subarraySum(nums: number[], k: number): number {
  const map=new Map([[0,1]]); let count=0,sum=0;
  for (const n of nums) { sum+=n; count+=map.get(sum-k)??0; map.set(sum,(map.get(sum)??0)+1); }
  return count;
}
```

## 5. Kadane's Algorithm
```typescript
function maxSubArray(nums: number[]): number {
  let maxSum=nums[0], cur=nums[0];
  for (let i=1;i<nums.length;i++) { cur=Math.max(nums[i],cur+nums[i]); maxSum=Math.max(maxSum,cur); }
  return maxSum;
}
// Max product — track both min and max (LC 152)
function maxProduct(nums: number[]): number {
  let max=nums[0],min=nums[0],res=nums[0];
  for (let i=1;i<nums.length;i++) {
    const cands=[nums[i],max*nums[i],min*nums[i]];
    max=Math.max(...cands); min=Math.min(...cands); res=Math.max(res,max);
  }
  return res;
}
```

## 6. Complexity Table
| Operation | Array |
|-----------|-------|
| Access by index | O(1) |
| Insert at end (dynamic) | O(1) amortized |
| Insert at middle | O(n) |
| Delete at end | O(1) |
| Delete at middle | O(n) |
| Search unsorted | O(n) |
| Search sorted (binary) | O(log n) |

## 7. Gotchas
- Window length = `right - left + 1` (inclusive)
- Prefix array length is `n+1` (leading 0)
- String concat in loop = O(n²); use array+join
- `slice(i,j)` excludes index j
- Initialize prefix-sum map with `{0:1}`
- Kadane: update `cur` before `maxSum`

### Quick Reference — Java

```java
import java.util.*;

public class Main {
    public static void main(String[] args) {
        // Arrays & Strings quick reference
        System.out.println("=== Arrays & Strings ===");

        // Core data structure
        Map<String, Object> config = new LinkedHashMap<>();
        config.put("topic", "Arrays & Strings");
        config.put("complexity", "O(n)");

        for (var e : config.entrySet())
            System.out.println(e.getKey() + ": " + e.getValue());
    }
}
```

### Quick Reference — Python

```python
