**Interview Tip:** The single most important linked list habit is drawing a small example (3-5 nodes) before writing code. Show the interviewer exactly which pointers change. This makes your reasoning transparent and catches bugs before they appear in code. For any linked list problem, always test with: empty list, single node, two nodes, and the general case.

cheatSheet:
# Stacks & Queues Cheat Sheet

## 1. Core Concepts
- **Stack**: LIFO — Last In First Out. Push/pop at top. O(1) operations.
- **Queue**: FIFO — First In First Out. Enqueue at back, dequeue from front. O(1) with deque.
- Both can be implemented with arrays or linked lists.
- **Deque** (double-ended queue): push/pop at both ends O(1).

```typescript
// Stack using array
const stack: number[] = [];
stack.push(1);          // push
const top = stack.pop();  // pop
const peek = stack[stack.length - 1]; // peek

// Queue using array (inefficient — shift is O(n))
const queue: number[] = [];
queue.push(1);           // enqueue
const front = queue.shift(); // dequeue — O(n)!

// Queue using two stacks (amortized O(1))
class MyQueue {
  private inbox: number[] = [];
  private outbox: number[] = [];
  push(x: number): void { this.inbox.push(x); }
  pop(): number {
    if (!this.outbox.length)
      while (this.inbox.length) this.outbox.push(this.inbox.pop()!);
    return this.outbox.pop()!;
  }
  peek(): number {
    if (!this.outbox.length)
      while (this.inbox.length) this.outbox.push(this.inbox.pop()!);
    return this.outbox[this.outbox.length - 1];
  }
  empty(): boolean { return !this.inbox.length && !this.outbox.length; }
}
```

## 2. Monotonic Stack
```typescript
// Next Greater Element (LC 496) — monotonic decreasing stack
function nextGreaterElement(nums1: number[], nums2: number[]): number[] {
  const map = new Map<number, number>();
  const stack: number[] = [];
  for (const n of nums2) {
    while (stack.length && stack[stack.length-1] < n)
      map.set(stack.pop()!, n);
    stack.push(n);
  }
  return nums1.map(n => map.get(n) ?? -1);
}

// Largest Rectangle in Histogram (LC 84)
function largestRectangleArea(heights: number[]): number {
  const stack: number[] = []; // indices
  let maxArea = 0;
  const h = [...heights, 0]; // sentinel
  for (let i = 0; i < h.length; i++) {
    while (stack.length && h[stack[stack.length-1]] > h[i]) {
      const height = h[stack.pop()!];
      const width = stack.length ? i - stack[stack.length-1] - 1 : i;
      maxArea = Math.max(maxArea, height * width);
    }
    stack.push(i);
  }
  return maxArea;
}

// Daily Temperatures (LC 739) — monotonic decreasing stack
function dailyTemperatures(temperatures: number[]): number[] {
  const result = new Array(temperatures.length).fill(0);
  const stack: number[] = []; // indices
  for (let i = 0; i < temperatures.length; i++) {
    while (stack.length && temperatures[stack[stack.length-1]] < temperatures[i]) {
      const idx = stack.pop()!;
      result[idx] = i - idx;
    }
    stack.push(i);
  }
  return result;
}
```

## 3. BFS with Queue
```typescript
// Generic BFS template
function bfs(start: number, graph: number[][]): number[] {
  const visited = new Set([start]);
  const queue: number[] = [start];
  const result: number[] = [];
  while (queue.length) {
    const node = queue.shift(); // Use a proper deque in production
    result.push(node!);
    for (const neighbor of graph[node!]) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }
  return result;
}
// BFS level order (binary tree)
function levelOrder(root: TreeNode|null): number[][] {
  if (!root) return [];
  const result: number[][] = [];
  const queue: TreeNode[] = [root];
  while (queue.length) {
    const level: number[] = [];
    const size = queue.length;
    for (let i = 0; i < size; i++) {
      const node = queue.shift()!;
      level.push(node.val);
      if (node.left) queue.push(node.left);
      if (node.right) queue.push(node.right);
    }
    result.push(level);
  }
  return result;
}
```

## 4. Classic Stack Applications
```typescript
// Valid Parentheses (LC 20)
function isValid(s: string): boolean {
  const stack: string[] = [];
  const map: Record<string,string> = {')':'(',']':'[','}':'{'};
  for (const c of s) {
    if ('([{'.includes(c)) stack.push(c);
    else if (stack.pop() !== map[c]) return false;
  }
  return stack.length === 0;
}
// Min Stack (LC 155) — track minimum with auxiliary stack
class MinStack {
  private stack: number[] = [];
  private minStack: number[] = [];
  push(val: number): void {
    this.stack.push(val);
    this.minStack.push(Math.min(val, this.minStack[this.minStack.length-1]??Infinity));
  }
  pop(): void { this.stack.pop(); this.minStack.pop(); }
  top(): number { return this.stack[this.stack.length-1]; }
  getMin(): number { return this.minStack[this.minStack.length-1]; }
}
```

