cheatSheet:
# Dynamic Programming Cheat Sheet

## 1. Core Concepts
- **DP**: Optimal substructure + overlapping subproblems
- **Memoization** (top-down): recursive + cache. Natural if you can think recursively.
- **Tabulation** (bottom-up): fill table iteratively. Better for space optimization.
- **State**: the minimum information needed to define a subproblem
- **Transition**: how state (i) relates to states (i-1), (i-2), etc.

## 2. 1D DP Patterns
```typescript
// Climbing Stairs (LC 70) — Fibonacci DP
function climbStairs(n: number): number {
  if (n<=2) return n;
  let prev2=1, prev1=2;
  for (let i=3;i<=n;i++) { const cur=prev1+prev2; prev2=prev1; prev1=cur; }
  return prev1;
}
// House Robber (LC 198) — skip adjacent
function rob(nums: number[]): number {
  let prev2=0, prev1=0;
  for (const n of nums) { const cur=Math.max(prev1, prev2+n); prev2=prev1; prev1=cur; }
  return prev1;
}
// Coin Change (LC 322) — minimum coins
function coinChange(coins: number[], amount: number): number {
  const dp = new Array(amount+1).fill(Infinity);
  dp[0]=0;
  for (let a=1;a<=amount;a++)
    for (const c of coins)
      if (c<=a) dp[a]=Math.min(dp[a], dp[a-c]+1);
  return dp[amount]===Infinity ? -1 : dp[amount];
}
```

## 3. 2D DP Patterns
```typescript
// Longest Common Subsequence (LC 1143)
function longestCommonSubsequence(text1: string, text2: string): number {
  const m=text1.length, n=text2.length;
  const dp = Array.from({length:m+1},()=>new Array(n+1).fill(0));
  for (let i=1;i<=m;i++)
    for (let j=1;j<=n;j++)
      dp[i][j] = text1[i-1]===text2[j-1] ? dp[i-1][j-1]+1 : Math.max(dp[i-1][j],dp[i][j-1]);
  return dp[m][n];
}
// 0/1 Knapsack
function knapsack(weights: number[], values: number[], W: number): number {
  const n=weights.length;
  const dp = Array.from({length:n+1},()=>new Array(W+1).fill(0));
  for (let i=1;i<=n;i++)
    for (let w=0;w<=W;w++)
      dp[i][w] = w>=weights[i-1]
        ? Math.max(dp[i-1][w], dp[i-1][w-weights[i-1]]+values[i-1])
        : dp[i-1][w];
  return dp[n][W];
}
// Edit Distance (LC 72)
function minDistance(word1: string, word2: string): number {
  const m=word1.length, n=word2.length;
  const dp = Array.from({length:m+1},(_,i)=>Array.from({length:n+1},(_,j)=>i||j));
  for (let i=1;i<=m;i++)
    for (let j=1;j<=n;j++)
      dp[i][j] = word1[i-1]===word2[j-1] ? dp[i-1][j-1] : 1+Math.min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]);
  return dp[m][n];
}
```

## 4. Interval DP
```typescript
// Burst Balloons (LC 312) — think about last balloon to burst
function maxCoins(nums: number[]): number {
  const arr = [1,...nums,1]; // padding
  const n=arr.length;
  const dp = Array.from({length:n},()=>new Array(n).fill(0));
  for (let len=2;len<n;len++)
    for (let left=0;left<n-len;left++) {
      const right=left+len;
      for (let k=left+1;k<right;k++)
        dp[left][right]=Math.max(dp[left][right], arr[left]*arr[k]*arr[right]+dp[left][k]+dp[k][right]);
    }
  return dp[0][n-1];
}
```

## 5. State Machine DP (Stock Problems)
```typescript
// Best Time to Buy/Sell Stock with cooldown (LC 309)
function maxProfitCooldown(prices: number[]): number {
  let held=-prices[0], sold=0, rest=0;
  for (let i=1;i<prices.length;i++) {
    const prevHeld=held, prevSold=sold, prevRest=rest;
    held=Math.max(prevHeld, prevRest-prices[i]);
    sold=prevHeld+prices[i];
    rest=Math.max(prevRest, prevSold);
  }
  return Math.max(sold,rest);
}
```

## 6. Complexity Table
| Problem | Time | Space | Optimized Space |
|---------|------|-------|------------------|
| Fibonacci/Climbing Stairs | O(n) | O(n) | O(1) |
| Coin Change | O(n*amount) | O(amount) | O(amount) |
| LCS | O(m*n) | O(m*n) | O(min(m,n)) |
| Knapsack 0/1 | O(n*W) | O(n*W) | O(W) |
| Edit Distance | O(m*n) | O(m*n) | O(min(m,n)) |
| Longest Increasing Subsequence | O(n²) / O(n log n) | O(n) | O(n) |
| Matrix Chain Multiplication | O(n³) | O(n²) | O(n²) |

## 7. Gotchas
- Initialize dp correctly: often 0 or Infinity depending on min/max
- dp[0] base case: dp[0]=0 for coin change, dp[0]=1 for climbing stairs
- Space optimization: only need previous row/two rows → use rolling arrays
- LCS ≠ LPS (Longest Palindromic Subsequence): different DP
- For 'exactly' vs 'at most': different initialization
- Unbounded knapsack: inner loop in ascending order
- 0/1 knapsack: inner loop in DESCENDING order (or use 2D)

