Place N queens on an N×N chessboard so that no two queens attack each other (same row, column, or diagonal). This is the canonical backtracking problem — place one queen per row, and for each row try every column, pruning invalid positions immediately.

**Optimization:** Track attacked columns and both diagonals using sets/booleans instead of scanning the entire board each time.

```python
# Python — N-Queens with O(1) conflict checking
def solve_n_queens(n):
    result = []
    cols = set()        # columns already occupied
    diag1 = set()       # row - col (top-left to bottom-right)
    diag2 = set()       # row + col (top-right to bottom-left)
    board = ["." * n] * n

    def backtrack(row):
        if row == n:
            result.append(board[:])
            return
        for col in range(n):
            if col in cols or (row - col) in diag1 or (row + col) in diag2:
                continue
            # place queen
            cols.add(col)
            diag1.add(row - col)
            diag2.add(row + col)
            board[row] = "." * col + "Q" + "." * (n - col - 1)
            backtrack(row + 1)
            # remove queen (backtrack)
            cols.remove(col)
            diag1.remove(row - col)
            diag2.remove(row + col)
            board[row] = "." * n

    backtrack(0)
    return result

# Count solutions only (LeetCode 52)
def total_n_queens(n):
    cols = set()
    diag1 = set()
    diag2 = set()
    count = [0]

    def backtrack(row):
        if row == n:
            count[0] += 1
            return
        for col in range(n):
            if col in cols or (row - col) in diag1 or (row + col) in diag2:
                continue
            cols.add(col); diag1.add(row - col); diag2.add(row + col)
            backtrack(row + 1)
            cols.remove(col); diag1.remove(row - col); diag2.remove(row + col)

    backtrack(0)
    return count[0]

print(len(solve_n_queens(4)))  # 2 solutions for 4-Queens
print(total_n_queens(8))       # 92 solutions for 8-Queens
```

```java
// Java — N-Queens
import java.util.*;

public class NQueens {
    public List<List<String>> solveNQueens(int n) {
        List<List<String>> result = new ArrayList<>();
        char[][] board = new char[n][n];
        for (char[] row : board) Arrays.fill(row, '.');
        backtrack(board, 0, new HashSet<>(), new HashSet<>(),
                  new HashSet<>(), result);
        return result;
    }

    private void backtrack(char[][] board, int row, Set<Integer> cols,
                           Set<Integer> diag1, Set<Integer> diag2,
                           List<List<String>> result) {
        if (row == board.length) {
            List<String> snapshot = new ArrayList<>();
            for (char[] r : board) snapshot.add(new String(r));
            result.add(snapshot);
            return;
        }
        for (int col = 0; col < board.length; col++) {
            if (cols.contains(col) || diag1.contains(row - col)
                    || diag2.contains(row + col)) continue;
            board[row][col] = 'Q';
            cols.add(col); diag1.add(row - col); diag2.add(row + col);
            backtrack(board, row + 1, cols, diag1, diag2, result);
            board[row][col] = '.';
            cols.remove(col); diag1.remove(row - col); diag2.remove(row + col);
        }
    }
}
```

